class _AuthGateState extends State<AuthGate> {
  bool _isLoading = true;
  bool _isAuthenticated = false;

  @override
  void initState() {
    super.initState();
    _checkAuthStatus();
  }

  Future<void> _checkAuthStatus() async {
    final prefs = await SharedPreferences.getInstance();
    final isAuthenticated = prefs.getBool('is_authenticated') ?? false;
    final lastAuthTimestamp = prefs.getInt('last_auth_timestamp') ?? 0;

    // Session expires after 24 hours to prevent stale authentication
    final now = DateTime.now().millisecondsSinceEpoch;
    const sessionDuration = 24 * 60 * 60 * 1000; // 24 hours in milliseconds

    if (isAuthenticated && (now - lastAuthTimestamp) < sessionDuration) {
      setState(() {
        _isAuthenticated = true;
        _isLoading = false;
      });
    } else {
      // Clear stale authentication
      await prefs.setBool('is_authenticated', false);
      await prefs.remove('last_auth_timestamp');
      setState(() {
        _isAuthenticated = false;
        _isLoading = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    if (_isLoading) {
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }

    if (_isAuthenticated) {
      return const HomeScreen();
    }

    return const LoginScreen();
  }
}

class BiometricService {
  static final LocalAuthentication _localAuth = LocalAuthentication();

  /// Check if the device supports biometric authentication
  static Future<bool> isBiometricAvailable() async {
    try {
      final canAuthenticateWithBiometrics = await _localAuth.canCheckBiometrics;
      final canAuthenticate = await _localAuth.isDeviceSupported();
      return canAuthenticateWithBiometrics && canAuthenticate;
    } on PlatformException catch (_) {
      return false;
    }
  }

  /// Get available biometric types
  static Future<List<BiometricType>> getAvailableBiometrics() async {
    try {
      return await _localAuth.getAvailableBiometrics();
    } on PlatformException catch (_) {
      return <BiometricType>[];
    }
  }

  /// Authenticate using biometrics with strong security settings
  static Future<BiometricAuthResult> authenticate() async {
    try {
      final isAvailable = await isBiometricAvailable();
      if (!isAvailable) {
        return BiometricAuthResult(
          success: false,
          error: BiometricError.notAvailable,
          message: 'Biometric authentication is not available on this device.',
        );
      }

      final availableBiometrics = await getAvailableBiometrics();
      if (availableBiometrics.isEmpty) {
        return BiometricAuthResult(
          success: false,
          error: BiometricError.noBiometricsEnrolled,
          message: 'No biometrics are enrolled on this device.',
        );
      }

      final authenticated = await _localAuth.authenticate(
        localizedReason: 'Please authenticate to access the app',
        options: const AuthenticationOptions(
          stickyAuth: true,
          biometricOnly: true, // Prevent weak fallback to device PIN/pattern
          useErrorDialogs: true,
          sensitiveTransaction: true,
        ),
      );

      if (authenticated) {
        return BiometricAuthResult(
          success: true,
          message: 'Authentication successful.',
        );
      } else {
        return BiometricAuthResult(
          success: false,
          error: BiometricError.failed,
          message: 'Authentication failed. Please try again.',
        );
      }
    } on PlatformException catch (e) {
      return _handlePlatformException(e);
    } catch (e) {
      return BiometricAuthResult(
        success: false,
        error: BiometricError.unknown,
        message: 'An unexpected error occurred: ${e.toString()}',
      );
    }
  }

  static BiometricAuthResult _handlePlatformException(PlatformException e) {
    switch (e.code) {
      case 'NotAvailable':
        return BiometricAuthResult(
          success: false,
          error: BiometricError.notAvailable,
          message: 'Biometric authentication is not available.',
        );
      case 'NotEnrolled':
        return BiometricAuthResult(
          success: false,
          error: BiometricError.noBiometricsEnrolled,
          message: 'No biometrics enrolled. Please set up biometrics in device settings.',
        );
      case 'LockedOut':
        return BiometricAuthResult(
          success: false,
          error: BiometricError.lockedOut,
          message: 'Too many failed attempts. Biometric authentication is temporarily locked.',
        );
      case 'PermanentlyLockedOut':
        return BiometricAuthResult(
          success: false,
          error: BiometricError.permanentlyLockedOut,
          message: 'Biometric authentication is permanently locked. Please use your password.',
        );
      default:
        return BiometricAuthResult(
          success: false,
          error: BiometricError.unknown,
          message: 'Authentication error: ${e.message}',
        );
    }
  }

  /// Cancel any ongoing authentication
  static Future<void> cancelAuthentication() async {
    await _localAuth.stopAuthentication();
  }
}

enum BiometricError {
  notAvailable,
  noBiometricsEnrolled,
  failed,
  lockedOut,
  permanentlyLockedOut,
  unknown,
}

class BiometricAuthResult {
  final bool success;
  final BiometricError? error;
  final String message;

  BiometricAuthResult({
    required this.success,
    this.error,
    required this.message,
  });
}

